2204           if (Mode.inputsMayBePositiveZero() || Mode.outputsMayBePositiveZero())
2205             SrcDemandedMask |= fcNegSubnormal;
2206         }
2207 
2208         if (DemandedMask & fcNegZero)
2209           SrcDemandedMask |= fcNegSubnormal;
2210       }
2211 
2212       // Doubling a normal could have resulted in an infinity.
2213       if (DemandedMask & fcPosInf)
2214         SrcDemandedMask |= fcPosNormal;
2215       if (DemandedMask & fcNegInf)
2216         SrcDemandedMask |= fcNegNormal;
2217 
2218       if (SimplifyDemandedFPClass(I, 0, SrcDemandedMask, KnownLHS, Depth + 1))
2219         return I;
2220 
2221       Known = KnownFPClass::fadd_self(KnownLHS, Mode);
2222       KnownRHS = KnownLHS;
2223     } else {
2224       FPClassTest SrcDemandedMask = fcFinite;
2225 
2226       // inf + (-inf) = nan
2227       if (DemandedMask & fcNan)
2228         SrcDemandedMask |= fcNan | fcInf;
2229 
2230       if (DemandedMask & fcInf)
2231         SrcDemandedMask |= fcInf;
2232 
2233       if (SimplifyDemandedFPClass(I, 1, SrcDemandedMask, KnownRHS, Depth + 1) ||
2234           SimplifyDemandedFPClass(I, 0, SrcDemandedMask, KnownLHS, Depth + 1))
2235         return I;
2236 
2237       Type *EltTy = VTy->getScalarType();
2238       DenormalMode Mode = F.getDenormalMode(EltTy->getFltSemantics());
2239       Known = KnownFPClass::fadd(KnownLHS, KnownRHS, Mode);
2240     }
2241 
2242     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
2243     if (Constant *SingleVal =
2244             getFPClassConstant(VTy, ValidResults, /*IsCanonicalizing=*/true))
2245       return SingleVal;
2246 
2247     // Propagate known result to simplify edge case checks.
2248     bool ResultNotNan = (DemandedMask & fcNan) == fcNone;
2249     if (ResultNotNan) {
2250       KnownLHS.knownNot(fcNan);
2251       KnownRHS.knownNot(fcNan);
2252     }
2253 
2254     // With nnan: X + {+/-}Inf --> {+/-}Inf
2255     if (ResultNotNan && KnownRHS.isKnownAlways(fcInf | fcNan) &&
2256         KnownLHS.isKnownNever(fcNan))
2257       return I->getOperand(1);
2258 
2259     // With nnan: {+/-}Inf + X --> {+/-}Inf
2260     if (ResultNotNan && KnownLHS.isKnownAlways(fcInf | fcNan) &&
2261         KnownRHS.isKnownNever(fcNan))
2262       return I->getOperand(0);
2263 
2264     FastMathFlags InferredFMF =
2265         inferFastMathValueFlagsBinOp(FMF, ValidResults, KnownLHS, KnownRHS);
2266     if (InferredFMF != FMF) {
2267       I->setFastMathFlags(InferredFMF);
2268       return I;
2269     }
2270 
2271     return nullptr;
2272   }
2273   case Instruction::FMul: {
2274     KnownFPClass KnownLHS, KnownRHS;
2275 
2276     Value *X = I->getOperand(0);
2277     Value *Y = I->getOperand(1);
2278 
2279     FPClassTest SrcDemandedMask =
2280         DemandedMask & (fcNan | fcZero | fcSubnormal | fcNormal);
2281 
2282     if (DemandedMask & fcInf) {
2283       // mul x, inf = inf
2284       // mul large_x, large_y = inf
2285       SrcDemandedMask |= fcSubnormal | fcNormal | fcInf;
2286     }
2287 
2288     if (DemandedMask & fcNan) {
2289       // mul +/-inf, 0 => nan
2290       SrcDemandedMask |= fcZero | fcInf;
2291 
2292       // TODO: Mode check
2293       // mul +/-inf, sub => nan if daz
2294       SrcDemandedMask |= fcSubnormal;
2295     }
2296 
2297     // mul normal, subnormal = normal
2298     // Normal inputs may result in underflow.
2299     if (DemandedMask & (fcNormal | fcSubnormal))
2300       SrcDemandedMask |= fcNormal | fcSubnormal;
2301 
2302     if (DemandedMask & fcZero)
2303       SrcDemandedMask |= fcNormal | fcSubnormal;
2304 
2305     const SimplifyQuery &SQ = getSimplifyQuery();
2306     if (X == Y && isGuaranteedNotToBeUndef(X, SQ.AC, CxtI, SQ.DT, Depth + 1)) {
2307       if (SimplifyDemandedFPClass(I, 0, SrcDemandedMask, KnownLHS, Depth + 1))
2308         return I;
2309       Type *EltTy = VTy->getScalarType();
2310 
2311       DenormalMode Mode = F.getDenormalMode(EltTy->getFltSemantics());
2312       Known = KnownFPClass::square(KnownLHS, Mode);
2313 
2314       // Propagate known result to simplify edge case checks.
2315       if ((DemandedMask & fcNan) == fcNone)
2316         Known.knownNot(fcNan);
2317       if ((DemandedMask & fcPosInf) == fcNone)
2318         Known.knownNot(fcInf);
2319 
2320       FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
2321       if (Constant *Folded =
2322               getFPClassConstant(VTy, ValidResults, /*IsCanonicalizing=*/true))
2323         return Folded;
2324 
2325       if (Known.isKnownAlways(fcPosZero | fcPosInf | fcNan)) {
2326         assert(KnownLHS.isKnownNever(fcPosNormal));
2327 
2328         // We can skip the fabs if the source was already known positive.
2329         if (KnownLHS.isKnownAlways(fcPositive))
2330           return X;
2331 
2332         // => fabs(x), in case this was a -inf or -0.
2333         // Note: Dropping canonicalize.
2334         IRBuilderBase::InsertPointGuard Guard(Builder);
2335         Builder.SetInsertPoint(I);
2336         Value *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, FMF);
2337         Fabs->takeName(I);
2338         return Fabs;
2339       }
2340 
2341       return nullptr;
2342     }
2343 
2344     if (SimplifyDemandedFPClass(I, 1, SrcDemandedMask, KnownRHS, Depth + 1) ||
2345         SimplifyDemandedFPClass(I, 0, SrcDemandedMask, KnownLHS, Depth + 1))
2346       return I;
2347 
2348     // Propagate nnan-ness to sources to simplify source checks.
2349     if ((DemandedMask & fcNan) == fcNone) {
2350       KnownLHS.knownNot(fcNan);
2351       KnownRHS.knownNot(fcNan);
2352     }
2353 
2354     if (FMF.noInfs()) {
2355       // Flag implies inputs cannot be infinity.
2356       KnownLHS.knownNot(fcInf);
2357       KnownRHS.knownNot(fcInf);
2358     }
2359 
2360     bool NonNanResult = (DemandedMask & fcNan) == fcNone;
2361 
2362     // With no-nans/no-infs:
2363     // X * 0.0 --> copysign(0.0, X)
2364     // X * -0.0 --> copysign(0.0, -X)
2365     if ((NonNanResult || KnownLHS.isKnownNeverInfOrNaN()) &&
2366         KnownRHS.isKnownAlways(fcPosZero | fcNan)) {
2367       // => copysign(+0, lhs)
2368       // Note: Dropping canonicalize
2369       Value *Copysign = Builder.CreateCopySign(Y, X, FMF);
2370       Copysign->takeName(I);
2371       return Copysign;
2372     }
2373 
2374     if (KnownLHS.isKnownAlways(fcPosZero | fcNan) &&
2375         (NonNanResult || KnownRHS.isKnownNeverInfOrNaN())) {
2376       // => copysign(+0, rhs)
2377       // Note: Dropping canonicalize
2378       Value *Copysign = Builder.CreateCopySign(X, Y, FMF);
2379       Copysign->takeName(I);
2380       return Copysign;
2381     }
2382 
2383     if ((NonNanResult || KnownLHS.isKnownNeverInfOrNaN()) &&
2384         KnownRHS.isKnownAlways(fcNegZero | fcNan)) {
2385       // => copysign(0, fneg(lhs))
2386       // Note: Dropping canonicalize
2387       Value *Copysign =
2388           Builder.CreateCopySign(Y, Builder.CreateFNegFMF(X, FMF), FMF);
2389       Copysign->takeName(I);
2390       return Copysign;
2391     }
2392 
2393     if (KnownLHS.isKnownAlways(fcNegZero | fcNan) &&
2394         (NonNanResult || KnownRHS.isKnownNeverInfOrNaN())) {
2395       // => copysign(+0, fneg(rhs))
2396       // Note: Dropping canonicalize
2397       Value *Copysign =
2398           Builder.CreateCopySign(X, Builder.CreateFNegFMF(Y, FMF), FMF);
2399       Copysign->takeName(I);
